const query = $('Webhook - GET /vmm-sp-store').first().json.query || {};
const code  = (query.code || '').toString().trim().toUpperCase();

// Build a store object from one or more Employees rows for that store.
// E-mail = SM / store email. FM Email = Facility Manager email.
const buildStore = (rows) => {
  const first = rows[0].json;
  // Prefer the active SM's E-mail; fall back to the first available row.
  const smRow = rows.find(r =>
    (r.json['Status'] || '').toLowerCase() === 'active' &&
    (r.json['E-mail'] || '').trim()
  ) || rows[0];

  return {
    code:        (first['Store Code']   || '').toString().trim(),
    name:        (first['Store Name']   || '').toString().trim(),
    email:       (smRow.json['E-mail']  || '').toString().trim(),
    smEmail:     (smRow.json['E-mail']  || '').toString().trim(),
    fmEmail:     (first['FM Email']     || '').toString().trim(),
    fmName:      (first['FM Name']      || '').toString().trim(),
    managerName: (first['Manager Name'] || '').toString().trim(),
    asmName:     (first['ASM name']     || '').toString().trim(),
    city:        (first['City']         || '').toString().trim(),
    region:      (first['Region']       || '').toString().trim(),
    state:       (first['State']        || '').toString().trim(),
    zone:        (first['Zone']         || '').toString().trim(),
  };
};

const all = $input.all().filter(item => (item.json['Store Code'] || '').toString().trim());

// ── Single store lookup ──────────────────────────────────────────────
if (code) {
  const rows = all.filter(item =>
    (item.json['Store Code'] || '').toString().trim().toUpperCase() === code
  );
  if (!rows.length) {
    return [{ json: { found: false, code, message: 'Store code not found' } }];
  }
  return [{ json: { found: true, store: buildStore(rows) } }];
}

// ── All active stores (deduplicated by store code) ───────────────────
const storeMap = {};
for (const item of all) {
  const sc = (item.json['Store Code'] || '').toString().trim().toUpperCase();
  if (!sc) continue;
  if (!storeMap[sc]) storeMap[sc] = [];
  storeMap[sc].push(item);
}

const stores = Object.values(storeMap).map(buildStore);
return [{ json: { found: true, stores, count: stores.length } }];
